import { Product } from "model/productModel";

export const fetchProducts = async (category?: string): Promise<Product[]> => {
    const url = category ? `http://localhost:5001/api/products/${category}`
        : "http://localhost:5001/api/products";

    const response = await fetch(url);
    if (!response.ok) throw new Error("Failed to fetch products");
    return response.json();
};

export const fetchProductByName = async (name: string): Promise<Product> => {
    const response = await fetch(`http://localhost:5001/api/products/${encodeURIComponent(name)}`);

    if (!response.ok) {
        throw new Error("Failed to fetch product details");
    }

    return response.json();
};
